"use strict";(self.webpackChunkios_training=self.webpackChunkios_training||[]).push([[553],{9940:(e,t,a)=>{a.r(t),a.d(t,{data:()=>i});const i={key:"v-d6cece96",path:"/swift/",title:"Swift",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"A quick tour of some features",slug:"a-quick-tour-of-some-features",children:[]},{level:2,title:"Functions",slug:"functions",children:[]},{level:2,title:"Null safety",slug:"null-safety",children:[]},{level:2,title:"Enumerations",slug:"enumerations",children:[]},{level:2,title:"Object oriented programming features",slug:"object-oriented-programming-features",children:[]},{level:2,title:"Functional programming features",slug:"functional-programming-features",children:[]},{level:2,title:"Sources",slug:"sources",children:[]}],filePathRelative:"swift/README.md",git:{contributors:[{name:"yostane's Worldline github account",email:"86733850+wlybe@users.noreply.github.com",commits:1}]}}},4753:(e,t,a)=>{a.r(t),a.d(t,{default:()=>Y});var i=a(6252);const o=(0,i._)("h1",{id:"swift",tabindex:"-1"},[(0,i._)("a",{class:"header-anchor",href:"#swift","aria-hidden":"true"},"#"),(0,i.Uk)(" Swift")],-1),n=(0,i._)("p",null,"Swift is the official programming language for developing iOS, iPadOS, macOS, watchOS and AppleTV apps. It can also target other platforms such as Windows, Linux and Android.",-1),r=(0,i.Uk)("The source code of the language is hosted on "),s={href:"https://github.com/apple/swift",target:"_blank",rel:"noopener noreferrer"},l=(0,i.Uk)("apple/swift"),c=(0,i.Uk)(" github repository."),u=(0,i.uE)('<h2 id="a-quick-tour-of-some-features" tabindex="-1"><a class="header-anchor" href="#a-quick-tour-of-some-features" aria-hidden="true">#</a> A quick tour of some features</h2><p>Swift has modern and interesting features. Here some quick notable ones:</p><ul><li>Swift is statically typed and support implicit typing.</li><li><code>var</code> creates mutable variables.</li><li><code>let</code> creates immutable variables or constants depending on the type.</li><li>String interpolation is available with this syntax <code>\\(expression)</code>.</li><li>Parenthesis are not necessary in <code>if</code>, <code>for</code>, <code>while</code> and <code>switch</code> statements</li><li>for-each is the only type of for loop available</li><li>Types are not nullable by default. More about null safety later.</li><li>Functional programming features are supported such as Higher-order functions and functions as 1st class items.</li><li>Object oriented programming is supported however, interfaces are called protocols.</li></ul><p>The following code illustrates some of the features listed above.</p><iframe width="100%" height="700px" src="https://www.jdoodle.com/embed/v0/3tZJ"></iframe><p>In the following sections, we will delve into more features.</p><h2 id="functions" tabindex="-1"><a class="header-anchor" href="#functions" aria-hidden="true">#</a> Functions</h2><p>In the following, we use the terms argument and parameter interchangeably.</p><p>The declaration of functions in swift has the following peculiarities:</p><ul><li>Parameters are named and ordered. This means that when you call a function, you must specify the name of the arguments in the correct order.</li><li>A parameter can have different external and internal names by declaring it like this: <code>externalName internalName: Type</code>. The external name is also called an argument label.</li><li>You can make an parameter anonymous by setting this external name: <code>_</code>.</li><li>Arguments can have a default value. These are also called optional arguments.</li></ul><p>The following code snippet illustrates the above features.</p><iframe width="100%" height="700px" src="https://www.jdoodle.com/embed/v0/3v1n"></iframe><p>Swift allows to use functions as first class items. This allows to store function references into variables, pass functions as arguments to other functions and return a function from a function. Here is a brief summary of the features related to using a function as a 1st class item:</p><ul><li>A function can be assigned to a variable, passed as a function parameter or returned from a function.</li><li>A function type can be expressed as follows: <code>(typeOfParam1, typeOfParam2, etc) -&gt; returnType</code>.</li><li>The empty return type is Void.</li><li>We can use <code>typealias</code> to shorten writing long types.</li><li>Swift supports anonymous functions (also called lambda function) with the following syntax <code>{ argName1, argName2, etc. in // code }</code></li></ul><p>The following code snippet illustrates these features.</p><iframe width="100%" height="700px" src="https://www.jdoodle.com/embed/v0/3v1y"></iframe><p>Let&#39;s explore in the next section, one of the most amazing features of Swift: Null safety.</p><h2 id="null-safety" tabindex="-1"><a class="header-anchor" href="#null-safety" aria-hidden="true">#</a> Null safety</h2><p>In a nutshell, Null safety is a compiler feature that allows you to avoid the infamous <em>Null pointer exception</em> or <em>npe</em>. The Swift compiler provides null safety and reports errors and warning when we manipulate nullable (also called optional) values. Here is a list of null safety features provided by swift:</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>In Swift, the null value is called <code>nil</code></p></div><ul><li>All types are non optional by default. This means that we cannot assign <code>nil</code> to a variable or an argument. For example, this code fails <code>var s: String = nil</code>.</li><li>A type can be made optional by suffixing it with a <em>?</em>. For example: <code>var s: String? = nil</code>.</li><li>You cannot call a method or a property of an optional type, unless you do one of those possibilities: <ul><li>Use optional chaining with the <em>?</em> suffix.</li><li>Provide a default value with the <em>??</em> operator.</li><li>Unwrap the optional so that if becomes non optional.</li><li>Force unwrap the optional using the <em>!</em> suffix. This should never be used as it bypasses null safety checks.</li></ul></li></ul><div class="custom-container danger"><p class="custom-container-title">DANGER</p><p>You should never force unwrap with the <em>!</em>. Use other unwrapping techniques.</p></div><p>The following code illustrates null safety and how to use optional types:</p><iframe width="100%" height="700px" src="https://www.jdoodle.com/embed/v0/3IDP"></iframe><h2 id="enumerations" tabindex="-1"><a class="header-anchor" href="#enumerations" aria-hidden="true">#</a> Enumerations</h2><p>Enumerations allow to work with a group of values in a type-safe fashion. Swift provides many interesting features to enumerations:</p><ul><li>When the compiler can infer it, you can omit the name of the enumeration when you use one of its values.</li><li>Switch statements support enumerations.</li><li>You can easily iterate over an enum values by using <code>: CaseIterable</code>.</li><li>You can associate values or provide a raw value to enumeration cases. Raw values can be implicitly assigned.</li><li>You can use another enumeration as associated value, this is called <em>recursive enumeration</em>.</li></ul>',27),d=(0,i.Uk)("The following code illustrates some enumeration features. For further reading please consult "),h={href:"https://docs.swift.org/swift-book/LanguageGuide/Enumerations.html",target:"_blank",rel:"noopener noreferrer"},f=(0,i.Uk)("the official documentation"),p=(0,i.Uk)("."),m=(0,i.uE)('<iframe width="100%" height="700px" src="https://www.jdoodle.com/embed/v0/3K66"></iframe><h2 id="object-oriented-programming-features" tabindex="-1"><a class="header-anchor" href="#object-oriented-programming-features" aria-hidden="true">#</a> Object oriented programming features</h2><p>Swift supports most Object oriented features: classes, instances, encapsulation, simple inheritance, overriding, overloading, compositions, polymorphism and access control. There are some differences and additional features that are highlighted below:</p><ul><li>Multiple inheritance of classes and abstract classes are not supported.</li><li><em>Interfaces</em> are named <em>protocols</em> and have they are used a lot by swift developers to the point that there is a programming technique called <strong>Protocol oriented programming</strong>.</li><li>Extensions allow to add functions and conform to additional protocols outside of the original class declaration. This has many uses. For example, we can add methods to the standard String class.</li></ul><iframe width="100%" height="700px" src="https://www.jdoodle.com/embed/v0/41uW"></iframe><h2 id="functional-programming-features" tabindex="-1"><a class="header-anchor" href="#functional-programming-features" aria-hidden="true">#</a> Functional programming features</h2>',6),g=(0,i.Uk)("Functional programming revolves around "),w={href:"https://flexiple.com/ios/introduction-to-functional-programming-using-swift/",target:"_blank",rel:"noopener noreferrer"},b=(0,i.Uk)("three main concepts"),v=(0,i.Uk)(": pure functions, immutable objects and declarative programming."),y=(0,i._)("p",null,"Pure functions are functions that do not have side effects and will thus return always the same output given the same input. Swift allows to create pure functions but does not provide compile time guarantees that a function is pure.",-1),k=(0,i.Uk)("Immutable objects can be created using classes with constant properties (declared with "),x=(0,i._)("code",null,"let",-1),S=(0,i.Uk)("). Another common practice is to use structs for "),_={href:"https://stackoverflow.com/a/24232845",target:"_blank",rel:"noopener noreferrer"},U=(0,i.Uk)("many good reasons"),T=(0,i.Uk)(". One of the most notable ones is that structs are passed around by value and thus are more relevant in the functional paradigm where we want to avoid side effects."),j=(0,i.Uk)("Declarative programming can be easily explained as a way of programming that is centered "),A={href:"https://blog.ndepend.com/declarative-programming-depth/",target:"_blank",rel:"noopener noreferrer"},I=(0,i.Uk)("around telling what to do and not how to do it"),F=(0,i.Uk)(". This allows to obtain a clear and more maintainable code. For example, when we want to filter a table, a for loop is not declarative (we say imperative in this case) while the SQL syntax is considered declarative. Declarative programing is possible in Swift through chaining functions and passing functions as arguments. Indeed, we have seen earlier, Swift has 1st class support for functions. In addition to that, we can find declarative APIs in the standard Swift library and in Swift UI. The latter will be explored in a different chapter. For now, let's illustrate this part by processing a list of strings using only declarative APIs provided by Swift and no for loops."),O=(0,i._)("iframe",{width:"100%",height:"700px",src:"https://www.jdoodle.com/embed/v0/42L8"},null,-1),P=(0,i._)("h2",{id:"sources",tabindex:"-1"},[(0,i._)("a",{class:"header-anchor",href:"#sources","aria-hidden":"true"},"#"),(0,i.Uk)(" Sources")],-1),W={href:"https://docs.swift.org",target:"_blank",rel:"noopener noreferrer"},E=(0,i.Uk)("Swift official documentation"),N=(0,i.Uk)("."),q={},Y=(0,a(3744).Z)(q,[["render",function(e,t){const a=(0,i.up)("OutboundLink");return(0,i.wg)(),(0,i.iD)(i.HY,null,[o,n,(0,i._)("p",null,[r,(0,i._)("a",s,[l,(0,i.Wm)(a)]),c]),u,(0,i._)("p",null,[d,(0,i._)("a",h,[f,(0,i.Wm)(a)]),p]),m,(0,i._)("p",null,[g,(0,i._)("a",w,[b,(0,i.Wm)(a)]),v]),y,(0,i._)("p",null,[k,x,S,(0,i._)("a",_,[U,(0,i.Wm)(a)]),T]),(0,i._)("p",null,[j,(0,i._)("a",A,[I,(0,i.Wm)(a)]),F]),O,P,(0,i._)("ul",null,[(0,i._)("li",null,[(0,i._)("a",W,[E,(0,i.Wm)(a)]),N])])],64)}]])},3744:(e,t)=>{t.Z=(e,t)=>{const a=e.__vccOpts||e;for(const[e,i]of t)a[e]=i;return a}}}]);